export interface AudioGenerationRequest {
    text: string;
    voice?: string;
    speed?: number;
    pitch?: number;
    format?: string;
}

export interface AudioGenerationResult {
    id: string;
    text: string;
    voice: string;
    url?: string;
    duration?: number;
    createdAt: number;
    provider: string;
    format: string;
}

export interface VoiceOption {
    id: string;
    name: string;
    language: string;
    gender: 'male' | 'female' | 'neutral';
    preview?: string;
}

export class AudioSystem {
    private engine: unknown;
    private isInitialized: boolean = false;
    private history: AudioGenerationResult[] = [];
    private voices: VoiceOption[] = [];
    private config = {
        provider: 'openai',
        endpoint: 'https://api.openai.com/v1/audio/speech',
        apiKey: '',
        model: 'tts-1',
        voice: 'alloy',
        speed: 1.0
    };

    constructor(engine: unknown) {
        this.engine = engine;
    }

    async init(): Promise<void> {
        if (this.isInitialized) return;

        console.log('[AudioSystem] 初始化音频生成系统...');

        this.loadConfig();
        this.loadHistory();
        this.initVoices();

        this.isInitialized = true;
        console.log('[AudioSystem] 音频生成系统初始化完成');
    }

    private loadConfig(): void {
        const saved = localStorage.getItem('audio_config');
        if (saved) {
            try {
                Object.assign(this.config, JSON.parse(saved));
            } catch (e) {
                console.error('[AudioSystem] 加载配置失败:', e);
            }
        }
    }

    private saveConfig(): void {
        localStorage.setItem('audio_config', JSON.stringify(this.config));
    }

    private loadHistory(): void {
        const saved = localStorage.getItem('audio_history');
        if (saved) {
            try {
                this.history = JSON.parse(saved);
            } catch (e) {
                console.error('[AudioSystem] 加载历史失败:', e);
            }
        }
    }

    private saveHistory(): void {
        localStorage.setItem('audio_history', JSON.stringify(this.history));
    }

    private initVoices(): void {
        this.voices = [
            { id: 'alloy', name: 'Alloy', language: 'en', gender: 'neutral' },
            { id: 'echo', name: 'Echo', language: 'en', gender: 'male' },
            { id: 'fable', name: 'Fable', language: 'en', gender: 'neutral' },
            { id: 'onyx', name: 'Onyx', language: 'en', gender: 'male' },
            { id: 'nova', name: 'Nova', language: 'en', gender: 'female' },
            { id: 'shimmer', name: 'Shimmer', language: 'en', gender: 'female' },
            { id: 'zh-CN-XiaoxiaoNeural', name: '晓晓', language: 'zh-CN', gender: 'female' },
            { id: 'zh-CN-YunxiNeural', name: '云希', language: 'zh-CN', gender: 'male' },
            { id: 'zh-CN-YunyangNeural', name: '云扬', language: 'zh-CN', gender: 'male' }
        ];
    }

    configure(config: Partial<typeof this.config>): void {
        Object.assign(this.config, config);
        this.saveConfig();
    }

    getConfig(): typeof this.config {
        return { ...this.config };
    }

    async generate(request: AudioGenerationRequest): Promise<AudioGenerationResult> {
        if (!this.config.apiKey) {
            return this.generateWithWebSpeech(request);
        }

        try {
            const response = await fetch(this.config.endpoint, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${this.config.apiKey}`
                },
                body: JSON.stringify({
                    model: this.config.model,
                    input: request.text,
                    voice: request.voice || this.config.voice,
                    speed: request.speed || this.config.speed,
                    response_format: request.format || 'mp3'
                })
            });

            if (!response.ok) {
                const error = await response.json().catch(() => ({}));
                throw new Error(error.error?.message || `生成失败: ${response.status}`);
            }

            const audioBlob = await response.blob();
            const audioUrl = URL.createObjectURL(audioBlob);

            const result: AudioGenerationResult = {
                id: `aud_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
                text: request.text,
                voice: request.voice || this.config.voice,
                url: audioUrl,
                createdAt: Date.now(),
                provider: this.config.provider,
                format: request.format || 'mp3'
            };

            this.history.unshift(result);
            if (this.history.length > 50) {
                this.history = this.history.slice(0, 50);
            }
            this.saveHistory();

            return result;
        } catch (error) {
            console.error('[AudioSystem] 生成音频失败:', error);
            return this.generateWithWebSpeech(request);
        }
    }

    private async generateWithWebSpeech(request: AudioGenerationRequest): Promise<AudioGenerationResult> {
        return new Promise((resolve) => {
            if (!('speechSynthesis' in window)) {
                resolve({
                    id: `aud_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
                    text: request.text,
                    voice: 'browser',
                    createdAt: Date.now(),
                    provider: 'browser',
                    format: 'live'
                });
                return;
            }

            const utterance = new SpeechSynthesisUtterance(request.text);
            utterance.rate = request.speed || this.config.speed;
            utterance.pitch = request.pitch || 1;

            const voices = speechSynthesis.getVoices();
            const targetVoice = voices.find(v => v.lang.startsWith('zh')) || voices[0];
            if (targetVoice) {
                utterance.voice = targetVoice;
            }

            const result: AudioGenerationResult = {
                id: `aud_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
                text: request.text,
                voice: targetVoice?.name || 'browser',
                createdAt: Date.now(),
                provider: 'browser',
                format: 'live'
            };

            utterance.onend = () => {
                this.history.unshift(result);
                this.saveHistory();
                resolve(result);
            };

            utterance.onerror = () => {
                resolve(result);
            };

            speechSynthesis.speak(utterance);
        });
    }

    speak(text: string, voice?: string): void {
        if ('speechSynthesis' in window) {
            const utterance = new SpeechSynthesisUtterance(text);
            const voices = speechSynthesis.getVoices();
            const targetVoice = voice
                ? voices.find(v => v.name === voice || v.voiceURI === voice)
                : voices.find(v => v.lang.startsWith('zh')) || voices[0];

            if (targetVoice) {
                utterance.voice = targetVoice;
            }

            utterance.rate = this.config.speed;
            speechSynthesis.speak(utterance);
        }
    }

    stop(): void {
        if ('speechSynthesis' in window) {
            speechSynthesis.cancel();
        }
    }

    pause(): void {
        if ('speechSynthesis' in window) {
            speechSynthesis.pause();
        }
    }

    resume(): void {
        if ('speechSynthesis' in window) {
            speechSynthesis.resume();
        }
    }

    getVoices(): VoiceOption[] {
        return [...this.voices];
    }

    getBrowserVoices(): SpeechSynthesisVoice[] {
        if ('speechSynthesis' in window) {
            return speechSynthesis.getVoices();
        }
        return [];
    }

    getHistory(): AudioGenerationResult[] {
        return [...this.history];
    }

    deleteAudio(id: string): boolean {
        const index = this.history.findIndex(a => a.id === id);
        if (index > -1) {
            const audio = this.history[index];
            if (audio.url && audio.url.startsWith('blob:')) {
                URL.revokeObjectURL(audio.url);
            }
            this.history.splice(index, 1);
            this.saveHistory();
            return true;
        }
        return false;
    }

    clearHistory(): void {
        this.history.forEach(audio => {
            if (audio.url && audio.url.startsWith('blob:')) {
                URL.revokeObjectURL(audio.url);
            }
        });
        this.history = [];
        this.saveHistory();
    }

    async downloadAudio(audioUrl: string, filename?: string): Promise<void> {
        try {
            let blob: Blob;

            if (audioUrl.startsWith('blob:')) {
                const response = await fetch(audioUrl);
                blob = await response.blob();
            } else {
                const response = await fetch(audioUrl);
                blob = await response.blob();
            }

            const url = URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            a.download = filename || `ai_audio_${Date.now()}.mp3`;
            document.body.appendChild(a);
            a.click();
            document.body.removeChild(a);
            URL.revokeObjectURL(url);
        } catch (error) {
            console.error('[AudioSystem] 下载音频失败:', error);
            throw error;
        }
    }

    getSpeeds(): Array<{ value: number; label: string }> {
        return [
            { value: 0.5, label: '0.5x (慢)' },
            { value: 0.75, label: '0.75x' },
            { value: 1.0, label: '1.0x (正常)' },
            { value: 1.25, label: '1.25x' },
            { value: 1.5, label: '1.5x' },
            { value: 2.0, label: '2.0x (快)' }
        ];
    }

    getFormats(): Array<{ value: string; label: string }> {
        return [
            { value: 'mp3', label: 'MP3' },
            { value: 'opus', label: 'Opus' },
            { value: 'aac', label: 'AAC' },
            { value: 'flac', label: 'FLAC' }
        ];
    }

    estimateDuration(text: string, speed: number = 1.0): number {
        const charsPerSecond = 15 * speed;
        return Math.ceil(text.length / charsPerSecond);
    }
}

export default AudioSystem;
